"use client";

import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { Points, PointMaterial } from "@react-three/drei";
import { useState, useRef, useMemo } from "react";
import * as THREE from "three";

function ParticleCloud() {
  const ref = useRef<THREE.Points>(null);
  const [sphere] = useState(() => {
    // Generate random points in a sphere
    const count = 3000;
    const array = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
       const u = Math.random();
       const v = Math.random();
       const theta = u * 2.0 * Math.PI;
       const phi = Math.acos(2.0 * v - 1.0);
       const r = Math.cbrt(Math.random()) * 2.5;
       const sinPhi = Math.sin(phi);
       const x = r * sinPhi * Math.cos(theta);
       const y = r * sinPhi * Math.sin(theta);
       const z = r * Math.cos(phi);
       
       array[i*3] = x;
       array[i*3+1] = y;
       array[i*3+2] = z;
    }
    return array;
  });

  const { pointer } = useThree();

  useFrame((state, delta) => {
    if (ref.current) {
      ref.current.rotation.x -= delta / 10;
      ref.current.rotation.y -= delta / 15;
      
      // Slight movement based on pointer to give depth
      const targetX = (pointer.x * Math.PI) / 8;
      const targetY = (pointer.y * Math.PI) / 8;
      
      ref.current.rotation.y += (targetX - ref.current.rotation.y) * 0.05;
      ref.current.rotation.x += (targetY - ref.current.rotation.x) * 0.05;
    }
  });

  return (
    <group rotation={[0, 0, Math.PI / 4]}>
      <Points ref={ref} positions={sphere} stride={3} frustumCulled={false}>
        <PointMaterial
          transparent
          color="#3b82f6"
          size={0.015}
          sizeAttenuation={true}
          depthWrite={false}
          opacity={0.8}
        />
      </Points>
    </group>
  );
}

export function Hero3D() {
  return (
    <div className="absolute inset-0 w-full h-full z-0 opacity-60">
      <Canvas camera={{ position: [0, 0, 3] }} dpr={[1, 2]}>
        <ParticleCloud />
      </Canvas>
    </div>
  );
}
